#include <stdio.h>

int main() {
    int niz[] = {10, 20, 30, 40, 50};
    int *p = niz;
    /* Ispis prvog i drugog clana niza */
    printf("Prvi clan: %d\n", *p);
    printf("Drugi clan: %d\n", *(p + 1));
    
    /* Pomjeranje pokazivaca na posljednji clan */
    p += 4;
    printf("Posljednji clan: %d\n", *p);
    
    /* Vracanje pokazivaca za jedno mjesto unazad */
    p--;
    printf("Pretposljednji clan: %d\n", *p);


    return 0;
}
